CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
DO $$ BEGIN CREATE TYPE user_role AS ENUM ('ADMIN','SALES','WAREHOUSE','ACCOUNTS'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE customer_status AS ENUM ('LEAD','ACTIVE','INACTIVE'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE customer_type AS ENUM ('RETAIL','WHOLESALE','DISTRIBUTOR'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE challan_status AS ENUM ('DRAFT','CONFIRMED','CANCELLED'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE movement_type AS ENUM ('IN','OUT'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
CREATE TABLE IF NOT EXISTS users (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), name text NOT NULL, email text UNIQUE NOT NULL, password_hash text NOT NULL, role user_role NOT NULL, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS customers (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), name text NOT NULL, mobile text NOT NULL, email text, business_name text NOT NULL, gst_number text, type customer_type NOT NULL, address text, status customer_status NOT NULL DEFAULT 'LEAD', follow_up_date date, notes text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS customer_followups (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), customer_id uuid REFERENCES customers(id) ON DELETE CASCADE, note text NOT NULL, follow_up_date date, created_by uuid REFERENCES users(id), created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS products (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), name text NOT NULL, sku text UNIQUE NOT NULL, category text NOT NULL, unit_price numeric(12,2) NOT NULL CHECK(unit_price >= 0), current_stock integer NOT NULL DEFAULT 0 CHECK(current_stock >= 0), min_stock integer NOT NULL DEFAULT 0, location text NOT NULL, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS stock_movements (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), product_id uuid REFERENCES products(id), quantity integer NOT NULL CHECK(quantity > 0), type movement_type NOT NULL, reason text NOT NULL, created_by uuid REFERENCES users(id), created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS challans (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), challan_number text UNIQUE NOT NULL, customer_id uuid REFERENCES customers(id), status challan_status NOT NULL DEFAULT 'DRAFT', total_quantity integer NOT NULL DEFAULT 0, created_by uuid REFERENCES users(id), created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS challan_items (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), challan_id uuid REFERENCES challans(id) ON DELETE CASCADE, product_id uuid REFERENCES products(id), product_name text NOT NULL, sku text NOT NULL, unit_price numeric(12,2) NOT NULL, quantity integer NOT NULL CHECK(quantity > 0));
CREATE INDEX IF NOT EXISTS customers_search_idx ON customers USING gin (to_tsvector('simple', coalesce(name,'') || ' ' || coalesce(business_name,'') || ' ' || coalesce(mobile,'')));
